import { useState, useRef, useEffect } from 'react';
import { Mic, Square, RotateCcw, ArrowRight, Info } from 'lucide-react';
import { Btn, Bar, Spinner, Callout } from './ds';
import { transcribeBlob } from '../api';

export default function RecordTab({ onAnalyze, loading }) {
  const [phase,    setPhase]    = useState('idle');
  const [elapsed,  setElapsed]  = useState(0);
  const [progress, setProgress] = useState(0);
  const [text,     setText]     = useState('');
  const [err,      setErr]      = useState('');
  const [audioUrl, setAudioUrl] = useState(null);

  const recRef    = useRef(null);
  const chunks    = useRef([]);
  const timerRef  = useRef(null);
  const streamRef = useRef(null);

  const pad = n => String(n).padStart(2, '0');
  const fmt = s => `${pad(Math.floor(s / 60))}:${pad(s % 60)}`;

  const start = async () => {
    setErr(''); setText(''); setElapsed(0); setAudioUrl(null);
    chunks.current = [];
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;
      const mime = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
        ? 'audio/webm;codecs=opus'
        : MediaRecorder.isTypeSupported('audio/webm') ? 'audio/webm' : 'audio/ogg';
      const rec = new MediaRecorder(stream, { mimeType: mime });
      recRef.current = rec;
      rec.ondataavailable = e => { if (e.data?.size > 0) chunks.current.push(e.data); };
      rec.onstop = async () => {
        stream.getTracks().forEach(t => t.stop());
        const blob = new Blob(chunks.current, { type: mime });
        setAudioUrl(URL.createObjectURL(blob));
        await whisper(blob, mime);
      };
      rec.start(200);
      setPhase('rec');
      timerRef.current = setInterval(() => setElapsed(p => p + 1), 1000);
    } catch (e) {
      setErr(e.name === 'NotAllowedError'
        ? 'Microphone access was denied. Allow mic permissions in your browser and try again.'
        : `Mic error: ${e.message}`);
      setPhase('err');
    }
  };

  const stop = () => {
    clearInterval(timerRef.current);
    recRef.current?.stop();
    setPhase('tx');
    setProgress(0);
  };

  const whisper = async (blob, mime) => {
    let iv;
    try {
      iv = setInterval(() => setProgress(p => p < 85 ? p + Math.random() * 9 : p), 500);
      const t = await transcribeBlob(blob, mime);
      clearInterval(iv);
      setProgress(100);
      if (!t?.trim()) { setErr('No speech detected. Speak clearly and try again.'); setPhase('err'); return; }
      setText(t.trim());
      setPhase('done');
    } catch (e) {
      clearInterval(iv);
      setErr(`Transcription failed: ${e.message}`);
      setPhase('err');
    }
  };

  const reset = () => {
    setPhase('idle'); setElapsed(0); setText(''); setErr(''); setProgress(0);
    if (audioUrl) { URL.revokeObjectURL(audioUrl); setAudioUrl(null); }
  };

  useEffect(() => () => {
    clearInterval(timerRef.current);
    streamRef.current?.getTracks().forEach(t => t.stop());
  }, []);

  const isRec  = phase === 'rec';
  const isTx   = phase === 'tx';
  const isDone = phase === 'done';
  const isErr  = phase === 'err';

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>

      {/* ── Recording stage ── */}
      <div style={{
        background: isRec ? '#1A0800' : 'var(--white)',
        border: `1px solid ${isRec ? 'var(--bear)' : 'var(--rule)'}`,
        borderRadius: 'var(--r-lg)', overflow: 'hidden',
        transition: 'background 0.4s, border-color 0.4s',
      }}>

        {/* Waveform + timer */}
        <div style={{
          padding: '28px 22px',
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 18,
          borderBottom: `1px solid ${isRec ? '#2a1208' : 'var(--rule)'}`,
        }}>
          {/* Bars */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 3, height: 44 }}>
            {Array.from({ length: 30 }).map((_, i) => (
              <div key={i} style={{
                width: 3, borderRadius: 2,
                background: isRec ? 'var(--bear)' : 'var(--rule-2)',
                transformOrigin: 'center',
                transition: 'background 0.4s',
                animation: isRec
                  ? `wave ${0.4 + (i % 6) * 0.1}s ease-in-out ${i * 0.03}s infinite alternate`
                  : 'none',
                height: '100%',
                opacity: isRec ? 1 : 0.5,
              }} />
            ))}
          </div>

          {/* Timer */}
          <div style={{
            fontFamily: 'var(--f-data)', fontSize: 34, fontWeight: 500,
            letterSpacing: '0.05em',
            color: isRec ? 'var(--bear)' : isTx ? 'var(--info)' : 'var(--ink-5)',
            transition: 'color 0.3s',
          }}>
            {fmt(elapsed)}
          </div>

          {/* Label */}
          <p style={{ fontSize: 12.5, color: isRec ? '#f87171' : 'var(--ink-4)', margin: 0, textAlign: 'center' }}>
            {phase === 'idle' && 'Press start to capture the client conversation'}
            {phase === 'rec'  && <span style={{ animation: 'blink 1.4s infinite' }}>● Recording — speak now</span>}
            {phase === 'tx'   && 'Sending audio to Whisper for transcription…'}
            {phase === 'done' && <span style={{ color: 'var(--bull)' }}>Transcription complete</span>}
            {phase === 'err'  && <span style={{ color: 'var(--bear)' }}>Recording failed</span>}
          </p>
        </div>

        {/* Controls */}
        <div style={{ padding: '14px 18px', display: 'flex', alignItems: 'center', gap: 10, background: isRec ? '#120600' : undefined }}>
          {phase === 'idle' && (
            <Btn look='danger' Icon={Mic} onClick={start} disabled={loading}>Start Recording</Btn>
          )}
          {phase === 'rec' && (
            <button onClick={stop} style={{
              display: 'flex', alignItems: 'center', gap: 7,
              padding: '8px 16px',
              background: 'var(--bear)', color: '#fff',
              border: 'none', borderRadius: 'var(--r)',
              fontFamily: 'var(--f-ui)', fontSize: 13, fontWeight: 500,
              cursor: 'pointer',
              animation: 'rec-pulse 1.5s infinite',
            }}>
              <Square size={14} strokeWidth={2} fill='currentColor' />
              Stop Recording
            </button>
          )}
          {isTx && <Spinner size={16} color='var(--info)' />}
          {(isDone || isErr) && (
            <>
              <Btn look='outline' Icon={RotateCcw} size='sm' onClick={reset}>Record again</Btn>
              {isDone && text && (
                <Btn look='fill' Icon={ArrowRight} onClick={() => onAnalyze(text)} disabled={loading}>
                  {loading ? 'Analyzing…' : 'Analyze'}
                </Btn>
              )}
            </>
          )}
        </div>

        {/* Progress bar */}
        {isTx && (
          <div style={{ padding: '0 18px 14px' }}>
            <Bar value={progress} color='var(--info)' h={3} />
            <p style={{ fontSize: 11, color: 'var(--ink-4)', marginTop: 5 }}>{Math.round(progress)}% — Whisper processing</p>
          </div>
        )}
      </div>

      {/* Error */}
      {isErr && err && <Callout type='error' onClose={reset}>{err}</Callout>}

      {/* Playback */}
      {audioUrl && (
        <div style={{ background: 'var(--white)', border: '1px solid var(--rule)', borderRadius: 'var(--r-md)', padding: '12px 14px' }}>
          <p style={{ fontSize: 11, fontWeight: 600, color: 'var(--ink-3)', marginBottom: 9, letterSpacing: '0.05em', textTransform: 'uppercase' }}>Playback</p>
          <audio controls src={audioUrl} style={{ width: '100%', height: 32 }} />
        </div>
      )}

      {/* Editable transcript */}
      {isDone && (
        <div style={{ background: 'var(--white)', border: '1px solid var(--bull-rule)', borderRadius: 'var(--r-md)', overflow: 'hidden' }}>
          <div style={{ padding: '9px 14px', background: 'var(--bull-bg)', borderBottom: '1px solid var(--bull-rule)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: 11, fontWeight: 600, color: 'var(--bull)', letterSpacing: '0.05em', textTransform: 'uppercase' }}>Transcript ready</span>
            <span style={{ fontSize: 11, fontFamily: 'var(--f-data)', color: 'var(--ink-4)' }}>{text.length} chars</span>
          </div>
          <textarea
            value={text}
            onChange={e => setText(e.target.value)}
            style={{ width: '100%', minHeight: 100, padding: '13px 14px', border: 'none', outline: 'none', fontSize: 13, lineHeight: 1.7, color: 'var(--ink)', fontFamily: 'var(--f-ui)', background: 'var(--white)', display: 'block' }}
          />
          <div style={{ padding: '10px 14px', background: 'var(--paper)', borderTop: '1px solid var(--rule)', display: 'flex', justifyContent: 'flex-end' }}>
            <Btn look='fill' Icon={ArrowRight} disabled={loading || !text.trim()} onClick={() => onAnalyze(text)}>
              {loading ? 'Analyzing…' : 'Analyze transcript'}
            </Btn>
          </div>
        </div>
      )}

      {/* Info */}
      {phase === 'idle' && (
        <Callout type='info'>
          <strong>How it works:</strong> Click Start Recording, speak the client conversation, then Stop. Audio is sent to <strong>OpenAI Whisper</strong> on your backend — not a browser API — so transcription is accurate.
        </Callout>
      )}
    </div>
  );
}
